Функция ПолучитьСальдоСчета(СсылкаНаСчет)
// Получаем оборотную ведомость по счету с учетом иерархии
ОборотнаяВедомость = ПолучитьОборотнуюВедомостьПоСчетам(
    Новый Структура("Параметры",
        "Субконто1", Неопределено,
        "Субконто2", Неопределено,
        "Субконто3", Неопределено,
        "Период", ДатаНачало(),
        "ПериодПо", ДатаКонец(),
        "Счет", СсылкаНаСчет,
        "Иерархия", Истина));

Если ОборотнаяВедомость.Количество() > 0 Тогда
    Если Счет.Вид.Сравнить(ВидСчета.Пассивный) = 0 Тогда
        // Для пассивных счетов возвращаем кредитовое сальдо
        Возврат ОборотнаяВедомость.Итог("Кредит");
    Иначе
        // Для активных и активно-пассивных счетов возвращаем дебетовое сальдо
        Возврат ОборотнаяВедомость.Итог("Дебет") - ОборотнаяВедомость.Итог("Кредит");
КонецЕсли;
КонецЕсли;
Возврат 0; // если нет данных или ошибка
КонецФункции
